(window.webpackJsonp=window.webpackJsonp||[]).push([[308],{935:function(n,s){n.exports="\x3c!-- \ntitle: Webpack入门\nsort: \n--\x3e \n\n> `npm install webpack webpack-cli --save-dev`\n>\n> 用于打包编译代码\n\n## 入门\n\n1. 配置文件`webpack.config.js`\n\n```js\n'use strict'\nconst path = require('path');\nmodule.exports = {\n  // 打包入口\n  entry: {\n    index: './src/index.js',\n  },\n  // 输出地址\n  output: {\n    path: path.join(__dirname, 'dist'),\n    filename: 'index.js'\n  },\n  // 开发环境\n  mode: 'production',\n}\n```\n\n2. 源代码`src`\n\n```js\n// sayhi.js\nexport function sayHi() {\n  return 'Hello Webpack~'\n}\n// index.js\nimport {sayHi} from './sayhi'\ndocument.write(sayHi())\n```\n\n3. 引用代码`dist/index.html`\n\n```html\n<script src=\"./index.js\" type=\"text/javascript\"><\/script>\n```\n\n4. 编译\n\n```bash\n# 不够优雅的方法\n./node_modules/.bin/webpack\n\n# package.json添加\n\"build\": \"webpack\"\n# 运行\nnpm run build\n\n```\n\n## 引入css\n\n> `npm i style-loader css-loader -D`\n\n1. 配置文件\n\n```json\nmodule: {\n  rules: [\n    {\n      test: /.css$/,\n      use: [\n        'style-loader',\n        'css-loader'\n      ]\n    },\n  ]\n},\n```\n\n2. 添加css文件，执行编译命令"}}]);